module edge_detector (
	input clk,
	input rst,
	input d,
	output reg edge_detected);

	reg d_prev;

	always @(posedge clk) begin
		if (rst)
			d_prev <= 0;
		else
			d_prev <= d;
	end

	always @(posedge clk) begin
		if (rst)
			edge_detected <= 0;
		else
			edge_detected <= d & ~d_prev;
	end

  always @(*) begin
    if (1'b0) begin
      if (d_prev & ~d) begin
        edge_detected <= 1;
      end else begin
        edge_detected <= 0;
      end;
    end
  end

endmodule

